import { type Browser, type BrowserContext } from 'playwright';

import { logAgentAudit } from '@/features/ai/agent-runtime/audit';
import {
  appendTaskTypeToPrompt,
  isExtractionStep,
} from '@/features/ai/agent-runtime/planning/utils';
import { runAgentBrowserControl, runAgentTool } from '@/features/ai/agent-runtime/tools';
import { type PlanStep, type PlannerMeta } from '@/shared/contracts/agent-runtime';
import unknownToErrorMessage from '@/shared/utils/error-formatting';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export async function executeTool(args: {
  step: PlanStep;
  stepIndex: number;
  hasBrowserContext: boolean;
  runPrompt: string;
  taskType: PlannerMeta['taskType'] | null;
  runId: string;
  agentBrowser: string | undefined;
  runHeadless: boolean | undefined;
  sharedBrowser: Browser | null;
  sharedContext: BrowserContext | null;
}): Promise<{
  toolResult: Awaited<ReturnType<typeof runAgentTool>> | null;
  toolError: unknown;
  toolName: string;
  shouldRunExtraction: boolean;
  shouldInitializeBrowser: boolean;
}> {
  const { step, stepIndex, runPrompt, taskType, runId } = args;

  const shouldInitializeBrowser = !args.hasBrowserContext || stepIndex === 0;
  const shouldRunExtraction = isExtractionStep(step, runPrompt, taskType);
  const toolName = shouldInitializeBrowser || shouldRunExtraction ? 'playwright' : 'snapshot';
  const toolStart = Date.now();

  const toolContext = {
    type: 'tool-execution',
    toolName,
    stepId: step.id,
    stepTitle: step.title,
    shouldRunExtraction,
    shouldInitializeBrowser,
  };

  await logAgentAudit(runId, 'info', 'Tool execution started.', toolContext);

  const toolTimeoutId = setTimeout(() => {
    void logAgentAudit(runId, 'warning', 'Tool execution taking longer than expected.', {
      ...toolContext,
      elapsedMs: Date.now() - toolStart,
    });
  }, 20000);

  let toolResult: Awaited<ReturnType<typeof runAgentTool>> | null = null;
  let toolError: unknown = null;

  try {
    toolResult = await runToolCore(args, { shouldInitializeBrowser, shouldRunExtraction });
  } catch (error) {
    logClientError(error);
    toolError = error;
  } finally {
    clearTimeout(toolTimeoutId);
    await logToolFinish({ runId, toolContext, toolResult, toolError, toolStart });
  }

  return { toolResult, toolError, toolName, shouldRunExtraction, shouldInitializeBrowser };
}

async function runToolCore(
  args: {
    step: PlanStep;
    runPrompt: string;
    taskType: PlannerMeta['taskType'] | null;
    runId: string;
    agentBrowser: string | undefined;
    runHeadless: boolean | undefined;
    sharedBrowser: Browser | null;
    sharedContext: BrowserContext | null;
  },
  config: { shouldInitializeBrowser: boolean; shouldRunExtraction: boolean }
): Promise<Awaited<ReturnType<typeof runAgentTool>>> {
  const { step, runId, sharedBrowser, sharedContext } = args;

  if (!config.shouldInitializeBrowser && !config.shouldRunExtraction) {
    return runAgentBrowserControl({
      runId,
      action: 'snapshot',
      stepId: step.id,
      stepLabel: step.title,
    });
  }

  const toolPrompt = appendTaskTypeToPrompt(
    args.runPrompt,
    config.shouldRunExtraction ? 'extract_info' : args.taskType
  );

  return runAgentTool(
    {
      name: 'playwright',
      input: {
        prompt: toolPrompt,
        browser: args.agentBrowser && args.agentBrowser !== '' ? args.agentBrowser : 'chromium',
        runId,
        ...(typeof args.runHeadless === 'boolean' && {
          runHeadless: args.runHeadless,
        }),
        stepId: step.id,
        stepLabel: step.title,
      },
    },
    sharedBrowser ?? undefined,
    sharedContext ?? undefined
  );
}

async function logToolFinish(options: {
  runId: string;
  toolContext: object;
  toolResult: Awaited<ReturnType<typeof runAgentTool>> | null;
  toolError: unknown;
  toolStart: number;
}): Promise<void> {
  const { runId, toolContext, toolResult, toolError, toolStart } = options;
  const errorMessage = toolResult?.error ?? unknownToErrorMessage(toolError);
  await logAgentAudit(runId, toolError !== null ? 'error' : 'info', 'Tool execution finished.', {
    ...toolContext,
    ok: toolResult?.ok ?? false,
    error: errorMessage,
    durationMs: Date.now() - toolStart,
  });
}

import { logAgentAudit } from '@/features/ai/agent-runtime/audit';
import {
  type AgentCheckpoint,
  agentCheckpointSchema,
  type AgentPlanPreferences,
  type AgentPlanSettings,
  type PlanStep,
  type PlannerMeta,
} from '@/shared/contracts/agent-runtime';
import type { ContextRegistryConsumerEnvelope } from '@/shared/contracts/ai-context-registry';
import type { InputJsonValue } from '@/shared/contracts/json';
import { getChatbotAgentRunDelegate } from '@/features/ai/agent-runtime/store-delegates';

export function parseCheckpoint(payload: unknown): AgentCheckpoint | null {
  if (payload === null || payload === undefined || typeof payload !== 'object') return null;

  const result = agentCheckpointSchema.safeParse({
    ...(payload as Record<string, unknown>),
    updatedAt: (payload as Partial<AgentCheckpoint>).updatedAt ?? new Date().toISOString(),
  });

  return result.success ? result.data : null;
}

export function buildCheckpointState(payload: {
  steps: PlanStep[];
  activeStepId: string | null;
  lastError?: string | null;
  taskType?: PlannerMeta['taskType'] | null;
  resumeRequestedAt?: string | null;
  resumeProcessedAt?: string | null;
  approvalRequestedStepId?: string | null;
  approvalGrantedStepId?: string | null;
  checkpointBrief?: string | null;
  checkpointNextActions?: string[] | null;
  checkpointRisks?: string[] | null;
  checkpointStepId?: string | null;
  checkpointCreatedAt?: string | null;
  summaryCheckpoint?: number | null;
  settings?: AgentPlanSettings | null;
  preferences?: AgentPlanPreferences | null;
  contextRegistry?: ContextRegistryConsumerEnvelope | null;
}): AgentCheckpoint {
  const base = {
    steps: payload.steps,
    activeStepId: payload.activeStepId,
    lastError: payload.lastError ?? null,
    taskType: payload.taskType ?? null,
    resumeRequestedAt: payload.resumeRequestedAt ?? null,
    resumeProcessedAt: payload.resumeProcessedAt ?? null,
    approvalRequestedStepId: payload.approvalRequestedStepId ?? null,
    approvalGrantedStepId: payload.approvalGrantedStepId ?? null,
  };

  return {
    ...base,
    checkpointBrief: payload.checkpointBrief ?? null,
    checkpointNextActions: payload.checkpointNextActions ?? null,
    checkpointRisks: payload.checkpointRisks ?? null,
    checkpointStepId: payload.checkpointStepId ?? null,
    checkpointCreatedAt: payload.checkpointCreatedAt ?? null,
    summaryCheckpoint: payload.summaryCheckpoint ?? null,
    settings: payload.settings ?? null,
    preferences: payload.preferences ?? null,
    contextRegistry: payload.contextRegistry ?? null,
    updatedAt: new Date().toISOString(),
  };
}

export async function persistCheckpoint(payload: {
  runId: string;
  steps: PlanStep[];
  activeStepId: string | null;
  lastError?: string | null;
  taskType?: PlannerMeta['taskType'] | null;
  resumeRequestedAt?: string | null;
  resumeProcessedAt?: string | null;
  approvalRequestedStepId?: string | null;
  approvalGrantedStepId?: string | null;
  checkpointBrief?: string | null;
  checkpointNextActions?: string[] | null;
  checkpointRisks?: string[] | null;
  checkpointStepId?: string | null;
  checkpointCreatedAt?: string | null;
  summaryCheckpoint?: number | null;
  settings?: AgentPlanSettings | null;
  preferences?: AgentPlanPreferences | null;
  contextRegistry?: ContextRegistryConsumerEnvelope | null;
}): Promise<void> {
  const chatbotAgentRun = getChatbotAgentRunDelegate();
  if (chatbotAgentRun) {
    await chatbotAgentRun.update({
      where: { id: payload.runId },
      data: {
        planState: buildCheckpointState(payload) as InputJsonValue,
        activeStepId: payload.activeStepId,
        checkpointedAt: new Date(),
      },
    });
  }
  await logAgentAudit(payload.runId, 'info', 'Checkpoint saved.', {
    type: 'checkpoint-save',
    activeStepId: payload.activeStepId,
    stepCount: payload.steps.length,
  });
}

import { validateAndAddAgentLongTermMemory } from '@/features/ai/agent-runtime/memory';

type AddProblemSolutionMemoryOptions = {
  memoryKey: string;
  runId: string;
  personaId?: string | null;
  problem: string;
  countermeasure: string;
  context?: Record<string, unknown>;
  tags?: string[];
  model?: string | null;
  prompt?: string | null;
  summaryModel?: string | null;
};

export async function addProblemSolutionMemory(
  options: AddProblemSolutionMemoryOptions,
): Promise<void> {
  const {
    memoryKey,
    runId,
    problem,
    countermeasure,
    tags = [],
  } = options;

  if (memoryKey === '' || problem === '' || countermeasure === '') return;
  const summary = `Problem: ${problem} \u00b7 Countermeasure: ${countermeasure}`;

  const payload = buildMemoryPayload(options, summary, tags);

  await validateAndAddAgentLongTermMemory(payload);
}

function buildMemoryPayload(
  options: AddProblemSolutionMemoryOptions,
  summary: string,
  tags: string[],
) {
  const {
    memoryKey,
    runId,
    personaId,
    problem,
    countermeasure,
    context,
    model,
    prompt,
    summaryModel,
  } = options;

  return {
    memoryKey,
    runId,
    personaId: personaId ?? null,
    content: summary,
    summary,
    tags: ['problem-solution', ...tags],
    metadata: {
      problem,
      countermeasure,
      ...context,
    },
    importance: 4,
    model: model ?? undefined,
    summaryModel: summaryModel ?? undefined,
    prompt: prompt ?? undefined,
  };
}
